CREATE DATABASE shopping_db;
use shopping_db;
select * from customer_shopping limit 10;

-- --Total Revenue Generated by Male and female 
select gender ,sum(purchase_amount) from customer_shopping
group by  gender;

-- Pay higher than avg amount after using discount by customer
select customer_id , purchase_amount from customer_shopping
where discount_applied = 'Yes' and purchase_Amount >= (select avg(purchase_Amount) from customer_shopping);

-- Top 5 product with the highest average rating review
select item_purchased , round(avg(review_rating ),2) as "Average Review Rating" from customer_shopping
group by item_purchased
order by avg(review_rating) desc
limit 5

-- Compare average purchase amount between standard and express shipping
select shipping_type, round(avg(purchase_Amount),2) from customer_shopping 
where shipping_type in ("standard","express")
group by shipping_type

-- Compare average spend and total revenue between subcriber and non subcribers 
select subscription, COUNT(CUSTOMER_id) as total_customer,
round(avg(purchase_amount),1) as average_spend, sum(purchase_amount) as total_revenue from customer_shopping
where subscription in ("Yes" and "No")
group by subscription
order by average_spend,total_revenue desc;

-- Top 5 highest percentage of purchases with discound applied
select item_purchased, round(sum(case when discount_applied = 'Yes' then 1 else 0 end) / count(*) * 100,2) as discount_percentage
from customer_shopping
group by item_purchased
order by discount_percentage desc
limit 5 

