-- Segment customer into  new,returning, loyal based on their total number of previous purchase and count of each segment
with customer_type as(
select customer_id , previous_purchases,
case 
    when previous_purchases = 1 then "New"
	when previous_purchases between 2 and 10 then "Returning"
	else "Loyal" end as customer_segment from customer_shopping )
select customer_Segment, count(*) as "Number of Customer" from customer_type
group by customer_segment;

