-- Top 3 most purchased product by category
with item_count as (
select category, item_purchased,
count(customer_id) as total_order,
row_number() over(partition by category order by count(customer_id) desc) as item_rank
from customer_shopping
group by category,item_purchased)

select category,total_order,item_purchased,item_rank
from item_count
where  item_rank <=3;

-- Repeat buyer more than 5 by previous purchases
select subscription,
count(customer_id) as Repeat_customer
from customer_shopping
where previous_purchases >5
group by subscription;

-- Revenue contribution of each age group
select age_group,
sum(purchase_Amount) as Total_Revenue
from customer_shopping
group by age_group
order by total_revenue;